import{_ as p}from"./nyalra_kb-7135827b.js";import{_ as l}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as m,a0 as d,C as a}from"./framework-91490e6a.js";const u={},f=e("figure",null,[e("img",{src:p,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/8c3282ff44441c59822dd885b0119459.html",target:"_blank",rel:"noopener noreferrer"},b=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>最近，我每周都期待着东映官方发布的『忍者战队隐连者』的更新。</p><p>要问为什么我在众多战队系列中特别喜欢『忍者战队隐连者』的话，这个专栏的空间太小了写不下，请自己在我的note账号与twitter账号里搜索吧。首先忍者他们存在这一点就很好吧。</p><p>在『忍者战队隐连者』中，登场了名为「シロウネリ（白溶裔）」的妖怪。</p><p>白溶裔是一个以自己是世界上最丑陋的妖怪而自豪的存在，持有着“破破烂烂的东西才是至上”的价值观。当然，他自己的外貌也是破破烂烂的，毫无清洁感，如果这样的家伙被现代女性遇到的话，可能会被写成「被一个极其肮脏的男的搭讪（1/16）」的小作文吧。</p><p>白溶裔由于其特殊价值观，会把城市居民的衣物渐渐弄得破烂不堪。因为他「最讨厌那些珍惜物品的人」。当然，正义的忍者战队绝不会容忍这样的恶人，他们成功地将其击败。果然还是珍惜物品的感觉好啊！这也是这个儿童节目的教育性寓意。从头到尾都让人信服。家庭的爸爸妈妈们也可以放心地让他们的孩子看这个。</p><p>但是，我在这里想从成年人的角度来看待白溶裔的价值观。</p><p>从人类的主观来看，白溶裔无疑是应该被毫无怨言地铲除的最糟糕的妖怪，但从他自己的主观来看，他只是按照自己的审美感而生活着。因为他认为「丑陋的事物才是最好的」，所以将世界变得更加丑陋才是合理的。当然，他将自己的价值观强加给他人，那就另当别论了。忍者战队也并不是因此而愤怒的。</p><p>在现实生活中，这种情况也是存在的吧。即使是通常被认为是丑陋/肮脏的东西，在当事人的审美观中可能是绝佳之作。这正是多样性。既然坚信这一点，那就贯彻自己的价值观就好了，但很明显，这也会使他与绝大多数的人疏远。</p><p>有时，在互联网上，人们会被认为是「肮脏」的行为或人物所吸引。他们可能会认为「被这么多人骂还继续活动，真酷」。Rapper（说唱歌手）不也是这种感觉吗。不在乎世事，自己的舒适感和美丑才是一切。他们坚定地生活在自己的世界中，这吸引了粉丝。他们将暴力、辱骂甚至药物都视为酷炫的东西，他们的生活方式不是与白溶裔非常相似吗。即使不是rapper，也有许多人坚持自己的信念，坚信「这就是好的！」。最近风潮很大的铁道宅等人也是这样想的吧。不管周围有多少人批评，按照固定的角度拍摄火车就是他们的生活意义，所以没办法。我认为，这种特质本身是相当「不错」的。尽管细节上可能有争议，但坚定地追求自己喜欢的东西是酷的。</p><p>因此，白溶裔仅仅因为「只喜欢破烂的东西」和「最讨厌珍惜物品的人」这种不寻常的价值观而被消灭，我还是觉得有点可怜的。不，如果不消灭这家伙的话，只会给社会带来困扰。忍者战队在做正确的事情。隐藏起来，消灭邪恶，这就是他们的使命。</p><p>虽说如此，虽说如～此，这也是稍微与怪人的悲哀有点共鸣的夜晚。现实世界的白溶裔们，坚定地活下去吧。</p><hr><p><img src="'+l+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/3467b9d804c5cbb2bb457ec412b8548a.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【Doron Changer（ドロンチェンジャー）】这是忍者战队的变身道具。右边是项链。它的系统非常简单，只要按下按钮就会发出声音。金色的奢华感很不错，对吧？</p></blockquote>',15);function g(x,y){const r=a("ExternalLinkIcon"),n=a("RouterLink");return s(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("第26回／シロウネリの価値観"),o(r)])]),e("blockquote",null,[b,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_25.html"},{default:m(()=>[t("【奈亚拉面壁自语】第25回｜讨厌酒会【230509】")]),_:1})])]),k])}const V=c(u,[["render",g],["__file","nyalra_kb_26.html.vue"]]);export{V as default};
